def test_mastery_to_ttm_enabled():
    from src.coach.agent import CoachAgent
    a = CoachAgent()
    if a.diagnostic_engine:
        summary = a.diagnostic_engine.get_mastery_summary()
        skills = summary.get("skills", {})
        if skills:
            assert len(list(skills.values())) > 0

def test_mastery_to_ttm_disabled():
    from src.coach.agent import CoachAgent
    a = CoachAgent()
    if not a.diagnostic_engine:
        assert a.ttm is None or a.ttm is not None

def test_mastery_to_ttm_empty():
    from src.coach.agent import CoachAgent
    a = CoachAgent()
    if a.diagnostic_engine:
        summary = a.diagnostic_engine.get_mastery_summary()
        assert isinstance(summary.get("skills", {}), dict)

def test_mastery_to_sdt_enabled():
    from src.coach.agent import CoachAgent
    a = CoachAgent()
    if a.diagnostic_engine:
        sig = a.diagnostic_engine.get_competence_signal()
        assert sig is None or isinstance(sig, (int, float))

def test_mastery_to_sdt_disabled():
    from src.coach.agent import CoachAgent
    a = CoachAgent()
    if not a.diagnostic_engine:
        assert a.sdt is None

def test_mastery_to_sdt_none():
    from src.coach.agent import CoachAgent
    a = CoachAgent()
    if a.diagnostic_engine:
        sig = a.diagnostic_engine.get_competence_signal()
        assert sig is None or isinstance(sig, (int, float))

def test_mastery_to_flow_enabled():
    from src.coach.agent import CoachAgent
    a = CoachAgent()
    if a.diagnostic_engine and a.flow:
        summary = a.diagnostic_engine.get_mastery_summary()
        skills = summary.get("skills", {})
        if skills:
            result = a.flow.compute_flow(skill_probs=list(skills.values()))
            assert "flow_channel" in result

def test_mastery_to_flow_disabled():
    from src.coach.agent import CoachAgent
    a = CoachAgent()
    if a.flow:
        result = a.flow.compute_flow(skill_probs=[0.5])
        assert "flow_channel" in result

def test_difficulty_default():
    from src.coach.agent import CoachAgent
    a = CoachAgent()
    if not a.diagnostic_engine:
        r = a.act("test")
        assert r["difficulty_contract"]["level"] == "medium"

def test_covered_topics_nonempty():
    from src.coach.agent import CoachAgent
    a = CoachAgent()
    if a.diagnostic_engine:
        m = a.diagnostic_engine.get_mastery_summary()
        skills = m.get("skills", {})
        if skills:
            topics = [f"{k}({v:.0%})" for k, v in skills.items()]
            assert len(topics) > 0

def test_covered_topics_empty():
    from src.coach.agent import CoachAgent
    a = CoachAgent()
    if a.diagnostic_engine:
        m = a.diagnostic_engine.get_mastery_summary()
        assert isinstance(m.get("skills", {}), dict)

@pytest.mark.skipif(not os.getenv("DEEPSEEK_API_KEY"), reason="need DEEPSEEK_API_KEY")
def test_llm_fallback():
    import os
    from src.coach.agent import CoachAgent
    bk = os.environ.pop("DEEPSEEK_API_KEY", None)
    try:
        a = CoachAgent()
        r = a.act("test")
        assert "action_type" in r
    finally:
        if bk:
            os.environ["DEEPSEEK_API_KEY"] = bk
